import { Outlet, Link } from "react-router-dom";

import { createUseStyles } from "react-jss";

const styles = createUseStyles({
  container: {
    display: "flex",

    listStyle: "none",
    gap: "10px",
  },
  li: {
    textDecoration: "none",
    color: "#58a6ff",
  },
});

const Layout = () => {
  const classes = styles();
  return (
    <>
      <div>
        <ul className={classes.container}>
          <li>
            <Link className={classes.li} to="html">
              HTML
            </Link>
          </li>
          <li>
            <Link className={classes.li} to="css">
              CSS
            </Link>
          </li>
          <li>
            <Link className={classes.li} to="Figma">
              Figma
            </Link>
          </li>
        </ul>
      </div>
      <Outlet />
    </>
  );
};
export default Layout;
